function WhatIsInfra({ program = 'infrastructure' }) {
  const data = programsContent[program] || programsContent.infrastructure;
  const sectionData = data.infraTypes;

  const isSpecializedProgram = program !== 'it-infrastructure' && program !== 'infrastructure';

  const icons = {
    "On-Prem": Server,
    "Cloud": Cloud,
    "Hybrid": RefreshCw,
    "Public Cloud": Cloud,
    "Private Cloud": Shield,
    "Hybrid Cloud": RefreshCw,
    "Multi-Cloud": Globe
  };

  if (isSpecializedProgram && sectionData.tools) {
    return (
      <section className="bg-white py-24 lg:py-32 overflow-hidden">
        <div className="max-w-6xl mx-auto px-6 relative z-10">
          {/* Section Header */}
          <div className="text-center mb-20">
            <h2 className="text-3xl md:text-4xl lg:text-5xl font-extrabold text-gray-900 tracking-tight leading-tight">
              {sectionData.title}
            </h2>
            {sectionData.subtitle && (
              <p className="text-gray-500 text-lg md:text-xl max-w-3xl mx-auto mt-5 leading-relaxed font-semibold">
                {sectionData.subtitle}
              </p>
            )}
          </div>

          {/* Tools Grid */}
          <motion.div 
            className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 lg:gap-10 items-stretch"
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, margin: "-100px" }}
            variants={{
              visible: {
                transition: {
                  staggerChildren: 0.1
                }
              }
            }}
          >
            {sectionData.tools.map((tool, index) => {
              const Logo = logoMap[tool.icon] || logoMap[tool.name] || Server;
              return (
                <motion.div
                  key={index}
                  variants={{
                    hidden: { opacity: 0, y: 30 },
                    visible: { opacity: 1, y: 0, transition: { duration: 0.5, ease: [0.16, 1, 0.3, 1] } }
                  }}
                  whileHover={{ scale: 1.03, y: -6 }}
                  transition={{ type: "spring", stiffness: 400, damping: 25 }}
                  className="group relative flex flex-col justify-between bg-white border border-gray-200/60 rounded-[20px] p-6 lg:p-8 cursor-pointer shadow-[0_10px_35px_rgba(0,0,0,0.015)] hover:shadow-[0_20px_45px_rgba(0,0,0,0.07)] hover:border-gray-300 transition-all duration-300 h-full overflow-hidden"
                >
                  {/* Subtle Gradient Glow Background on Hover */}
                  <div className={`absolute inset-0 bg-gradient-to-br ${tool.bgGlow || 'from-blue-500/5 to-purple-500/5'} opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none`}></div>

                  <div className="relative z-10 flex flex-col h-full justify-between space-y-4">
                    <div className="flex items-center gap-4">
                      {/* Logo Wrapper */}
                      <div className={`w-12 h-12 flex items-center justify-center bg-gradient-to-br ${tool.iconGlow || 'from-gray-50 to-gray-100'} border border-gray-100/50 rounded-xl group-hover:scale-110 transition-all duration-300`}>
                        <Logo size={24} />
                      </div>
                      
                      {/* Title */}
                      <h3 className="text-xl font-bold text-gray-900">
                        {tool.name}
                      </h3>
                    </div>

                    {/* Description */}
                    <p className="text-gray-500 text-sm leading-relaxed font-semibold">
                      {tool.description}
                    </p>
                  </div>
                </motion.div>
              );
            })}
          </motion.div>
        </div>
      </section>
    );
  }

  if (isSpecializedProgram && (sectionData.competencies || sectionData.platforms)) {
    return (
      <div className="flex flex-col">
        {/* Render Competencies Grid if present */}
        {sectionData.competencies && (
          <section className="bg-white py-24 lg:py-32 overflow-hidden border-b border-gray-100">
            <div className="max-w-6xl mx-auto px-6 relative z-10">
              <div className="text-center mb-20">
                <h2 className="text-3xl md:text-4xl lg:text-5xl font-extrabold text-gray-900 tracking-tight leading-tight">
                  {sectionData.competenciesTitle || "Core Competencies"}
                </h2>
              </div>
              <motion.div 
                className="grid grid-cols-1 md:grid-cols-3 gap-8 lg:gap-10 items-stretch"
                initial="hidden"
                whileInView="visible"
                viewport={{ once: true, margin: "-100px" }}
                variants={{
                  visible: {
                    transition: { staggerChildren: 0.15 }
                  }
                }}
              >
                {sectionData.competencies.map((comp, index) => {
                  const Logo = logoMap[comp.icon] || logoMap[comp.name] || Server;
                  const glowStyle = {
                    '--glow-color': comp.glowColor || 'rgba(0,0,0,0.02)',
                  };
                  return (
                    <motion.div
                      key={index}
                      variants={{
                        hidden: { opacity: 0, y: 40 },
                        visible: { opacity: 1, y: 0, transition: { duration: 0.7, ease: [0.16, 1, 0.3, 1] } }
                      }}
                      whileHover={{ scale: 1.02, y: -8 }}
                      transition={{ type: "spring", stiffness: 400, damping: 30 }}
                      style={glowStyle}
                      className="group relative flex flex-col justify-between bg-white border border-gray-200/80 rounded-[24px] p-8 transition-shadow duration-200 ease-out cursor-pointer shadow-[0_10px_30px_rgba(0,0,0,0.03)] hover:shadow-[0_20px_50px_var(--glow-color)] h-full overflow-hidden"
                    >
                      <div className={`absolute top-0 left-0 right-0 h-[6px] bg-gradient-to-r ${comp.accentColor}`}></div>
                      <div className="flex flex-col h-full justify-between">
                        <div>
                          <div className="w-16 h-16 flex items-center justify-center bg-gray-50 border border-gray-100 rounded-2xl mb-6 group-hover:scale-110 transition-transform duration-200 ease-out">
                            <Logo size={32} />
                          </div>
                          <h3 className="text-2xl font-bold text-gray-900 mb-4">
                            {comp.name}
                          </h3>
                          <p className="text-gray-500 text-sm leading-relaxed mb-6 font-medium">
                            {comp.description}
                          </p>
                          {comp.tags && (
                            <div className="flex flex-wrap gap-2.5">
                              {comp.tags.map((tag, tIdx) => (
                                <span 
                                  key={tIdx} 
                                  className="px-3 py-1 bg-gray-50 border border-gray-100 text-gray-600 rounded-full text-xs font-bold hover:bg-gray-100 hover:border-gray-200 transition-colors"
                                >
                                  {tag}
                                </span>
                              ))}
                            </div>
                          )}
                        </div>
                      </div>
                    </motion.div>
                  );
                })}
              </motion.div>
            </div>
          </section>
        )}

        {/* Render Platforms Grid if present */}
        {sectionData.platforms && (
          <section className="bg-white py-24 lg:py-32 overflow-hidden">
            <div className="max-w-6xl mx-auto px-6 relative z-10">
              <div className="text-center mb-20">
                <h2 className="text-3xl md:text-4xl lg:text-5xl font-extrabold text-gray-900 tracking-tight leading-tight">
                  {sectionData.title}
                </h2>
                {sectionData.subtitle && (
                  <p className="text-gray-500 text-lg md:text-xl max-w-3xl mx-auto mt-5 leading-relaxed font-semibold">
                    {sectionData.subtitle}
                  </p>
                )}
              </div>
              <motion.div 
                className="flex flex-wrap justify-center gap-6 lg:gap-8 max-w-6xl mx-auto"
                initial="hidden"
                whileInView="visible"
                viewport={{ once: true, margin: "-100px" }}
                variants={{
                  visible: {
                    transition: { staggerChildren: 0.15 }
                  }
                }}
              >
                {sectionData.platforms.map((provider, index) => {
                  const Logo = logoMap[provider.icon] || logoMap[provider.name] || Server;
                  const glowStyle = {
                    '--glow-color': provider.glowColor || 'rgba(0,0,0,0.02)',
                  };
                  return (
                    <motion.div
                      key={index}
                      variants={{
                        hidden: { opacity: 0, y: 40 },
                        visible: { opacity: 1, y: 0, transition: { duration: 0.7, ease: [0.16, 1, 0.3, 1] } }
                      }}
                      whileHover={{ scale: 1.02, y: -8 }}
                      transition={{ type: "spring", stiffness: 400, damping: 30 }}
                      style={glowStyle}
                      className="group relative flex flex-col justify-between bg-white border border-gray-200/80 rounded-[24px] p-6 transition-shadow duration-200 ease-out cursor-pointer shadow-[0_10px_30px_rgba(0,0,0,0.03)] hover:shadow-[0_20px_50px_var(--glow-color)] h-full overflow-hidden w-full md:w-[calc((100%-24px)/2)] lg:w-[calc((100%-64px)/3)]"
                    >
                      <div className={`absolute top-0 left-0 right-0 h-[6px] bg-gradient-to-r ${provider.accentColor}`}></div>
                      <div className="flex flex-col h-full justify-between">
                        <div>
                          <div className="w-14 h-14 flex items-center justify-center bg-gray-50 border border-gray-100 rounded-2xl mb-4 group-hover:scale-110 transition-transform duration-200 ease-out">
                            <Logo size={28} />
                          </div>
                          <h3 className="text-xl font-bold text-gray-900 mb-1">
                            {provider.name}
                          </h3>
                          {provider.badge && (
                            <div className="inline-flex items-center gap-1.5 px-2.5 py-0.5 rounded-full bg-gray-50 border border-gray-100/80 text-[9px] md:text-[10px] font-bold text-gray-600 mb-3 uppercase tracking-wider">
                              {provider.badge}
                            </div>
                          )}
                          <p className="text-gray-500 text-xs leading-relaxed mb-4 font-medium">
                            {provider.description}
                          </p>
                          {provider.tags && (
                            <div className="flex flex-wrap gap-1.5 mb-6">
                              {provider.tags.map((tag, tIdx) => (
                                <span 
                                  key={tIdx} 
                                  className="px-2 py-0.5 bg-gray-50 border border-gray-100 text-gray-600 rounded-md text-[10px] font-bold hover:bg-gray-100 hover:border-gray-200 transition-colors"
                                >
                                  {tag}
                                </span>
                              ))}
                            </div>
                          )}
                        </div>
                        {provider.stat && (
                          <div className="pt-4 border-t border-gray-100 flex items-center justify-between text-[9px] font-bold text-gray-400 uppercase tracking-widest mt-auto">
                            <span>Key Stat</span>
                            <span className={`bg-gradient-to-r ${provider.accentColor} bg-clip-text text-transparent`}>
                              {provider.stat}
                            </span>
                          </div>
                        )}
                      </div>
                    </motion.div>
                  );
                })}
              </motion.div>
            </div>
          </section>
        )}
      </div>
    );
  }

  if (isSpecializedProgram) {
    return (
      <section className="bg-white py-24 lg:py-32 overflow-hidden">
        <div className="max-w-6xl mx-auto px-6 relative z-10">
          {/* Section Header */}
          <div className="text-center mb-20">
            <h2 className="text-3xl md:text-4xl lg:text-5xl font-extrabold text-gray-900 tracking-tight leading-tight">
              {sectionData.title}
            </h2>
            {sectionData.subtitle && (
              <p className="text-gray-500 text-lg md:text-xl max-w-3xl mx-auto mt-5 leading-relaxed font-semibold">
                {sectionData.subtitle}
              </p>
            )}
          </div>

          {/* Cards Grid */}
          <motion.div 
            className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 lg:gap-10 items-stretch"
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, margin: "-100px" }}
            variants={{
              visible: {
                transition: {
                  staggerChildren: 0.15
                }
              }
            }}
          >
            {sectionData.types.map((provider, index) => {
              const Logo = logoMap[provider.icon] || logoMap[provider.name] || Server;
              const glowStyle = {
                '--glow-color': provider.glowColor || 'rgba(0,0,0,0.02)',
              };

              return (
                <motion.div
                  key={index}
                  variants={{
                    hidden: { opacity: 0, y: 40 },
                    visible: { opacity: 1, y: 0, transition: { duration: 0.7, ease: [0.16, 1, 0.3, 1] } }
                  }}
                  whileHover={{ scale: 1.02, y: -8 }}
                  transition={{ type: "spring", stiffness: 400, damping: 30 }}
                  style={glowStyle}
                  className="group relative flex flex-col justify-between bg-white border border-gray-200/80 rounded-[24px] p-8 transition-shadow duration-200 ease-out cursor-pointer shadow-[0_10px_30px_rgba(0,0,0,0.03)] hover:shadow-[0_20px_50px_var(--glow-color)] h-full overflow-hidden"
                >
                  {/* Subtle Top Gradient Accent Line */}
                  <div className={`absolute top-0 left-0 right-0 h-[6px] bg-gradient-to-r ${provider.accentColor}`}></div>

                  <div className="flex flex-col h-full justify-between">
                    <div>
                      {/* Logo Wrapper */}
                      <div className="w-16 h-16 flex items-center justify-center bg-gray-50 border border-gray-100 rounded-2xl mb-6 group-hover:scale-110 transition-transform duration-200 ease-out">
                        <Logo size={32} />
                      </div>

                      {/* Title */}
                      <h3 className="text-2xl font-bold text-gray-900 mb-2">
                        {provider.name}
                      </h3>

                      {/* Small badge under title */}
                      {provider.badge && (
                        <div className="inline-flex items-center gap-1.5 px-3 py-1 rounded-full bg-gray-50 border border-gray-100/80 text-[10px] md:text-xs font-bold text-gray-600 mb-5 uppercase tracking-wider">
                          {provider.badge}
                        </div>
                      )}

                      {/* Description */}
                      <p className="text-gray-500 text-sm leading-relaxed mb-6 font-medium">
                        {provider.description}
                      </p>

                      {/* Technology Tags */}
                      {provider.tags && (
                        <div className="flex flex-wrap gap-2.5 mb-8">
                          {provider.tags.map((tag, tIdx) => (
                            <span 
                              key={tIdx} 
                              className="px-3 py-1 bg-gray-50 border border-gray-100 text-gray-600 rounded-full text-xs font-bold hover:bg-gray-100 hover:border-gray-200 transition-colors"
                            >
                              {tag}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>

                    {/* Footer Stats Line */}
                    {provider.stat && (
                      <div className="pt-6 border-t border-gray-100 flex items-center justify-between text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-auto">
                        <span>Key Stat</span>
                        <span className={`bg-gradient-to-r ${provider.accentColor} bg-clip-text text-transparent`}>
                          {provider.stat}
                        </span>
                      </div>
                    )}
                  </div>
                </motion.div>
              );
            })}
          </motion.div>
        </div>
        
        {/* Required animation styling */}
        <style>{`
          @keyframes shimmer {
            0% { transform: translateX(-100%); }
            100% { transform: translateX(100%); }
          }
          .animate-shimmer {
            animation: shimmer 2.5s infinite linear;
          }
        `}</style>
      </section>
    );
  }

  // Fallback / Default IT Infrastructure circular models
  return (
    <section className="bg-gradient-to-b from-white to-gray-50 py-24 lg:py-28">
      <div className="max-w-6xl mx-auto px-6">
        {/* Section Title */}
        <div className="text-center mb-16">
          <h2 className="text-3xl md:text-4xl lg:text-5xl font-bold text-gray-900 tracking-tight">
            {sectionData.title}
          </h2>
        </div>
        
        {/* Circles Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-12 lg:gap-16 items-center justify-items-center">
          {sectionData.types.map((type, index) => {
            const IconComponent = logoMap[type.icon] || logoMap[type.name] || icons[type.name] || Server;
            return (
              <InfraTypeCircle 
                key={index}
                title={type.name}
                description={type.description}
                icon={IconComponent}
              />
            );
          })}
        </div>
      </div>
    </section>
  );
}

export default WhatIsInfra;